import json
import urllib.parse
import requests

TIMEOUT = 60

class NodeError(Exception):
    pass

def _log(*parts):
    print("[BAW] " + " ".join(str(p) for p in parts))

def _verify():
    return str(verify_ssl).strip().lower() not in ("false", "0", "no")

def _base():
    base = str(base_url).strip().rstrip("/")
    if not base:
        raise NodeError("base_url is required (e.g. https://baw-host:9443)")
    return base

def _auth_parts():
    headers = {"Accept": "application/json"}
    atype = str(auth_type or "basic").strip().lower()
    if atype == "bearer":
        tok = str(token or "").strip()
        if not tok:
            raise NodeError("token is required for bearer auth")
        headers["Authorization"] = "ZenApiKey " + tok
        _log("auth: bearer token")
        return headers, None
    user = str(username or "").strip()
    if not user:
        raise NodeError("username is required for basic auth")
    _log("auth: basic user=%s" % user)
    return headers, (user, str(password or ""))

def _send(method, url, query=None):
    headers, auth = _auth_parts()
    _log("%s %s" % (method, url))
    if query:
        _log("query: %s" % json.dumps(query, default=str)[:1500])
    _log("verify_ssl: %s" % _verify())
    try:
        r = requests.request(method, url, params=query, headers=headers,
                             auth=auth, verify=_verify(), timeout=TIMEOUT)
    except requests.RequestException as e:
        raise NodeError("request failed: %s: %s" % (type(e).__name__, e))
    _log("-> HTTP %s (%s)" % (r.status_code, "ok" if r.ok else "FAIL"))
    _log("final url: %s" % r.url)
    try:
        d = r.json()
    except ValueError:
        d = r.text
    if not r.ok:
        msg = d if isinstance(d, str) else json.dumps(d)[:400]
        raise NodeError("BAW %s: %s" % (r.status_code, msg))
    return r, d

base = _base()
instance = str(instance_id).strip()
if not instance:
    raise NodeError("instance_id is required")

p = str(parts or "all").strip()
_log("Get Service: instance_id=%s parts=%s" % (instance, p))

url = base + "/rest/bpm/wle/v1/serviceModel/" + urllib.parse.quote(instance, safe="")
query = {"parts": p} if p else None

r, d = _send("GET", url, query=query)
state = None
if isinstance(d, dict):
    body = d.get("data", d)
    state = body.get("executionState") or body.get("state") or body.get("status")
status_code = r.status_code
ok = r.ok
data = d
_log("execution state: %s" % state)
_log("output data: %s" % json.dumps(data, default=str)[:1500])
